-- 全列・全行を取得
SELECT * FROM employees;

-- 特定の列だけ取得
SELECT name, salary FROM employees;

-- WHERE句で条件を指定
SELECT name, salary
FROM employees
WHERE salary >= 350000;

-- 複数条件（AND / OR）
SELECT name, age, dept_id
FROM employees
WHERE dept_id = 1 AND age >= 25;

SELECT name FROM employees
WHERE dept_id = 1 OR dept_id = 2;

-- IN句で複数値を指定（ORの簡潔な書き方）
SELECT name FROM employees
WHERE dept_id IN (1, 2, 3);

-- LIKE句でパターンマッチ（% = 任意の文字列）
SELECT name FROM employees
WHERE name LIKE '山田%';  -- "山田"で始まる名前

-- BETWEEN で範囲指定
SELECT name, salary FROM employees
WHERE salary BETWEEN 300000 AND 400000;

-- NULLの判定（= ではなく IS NULL / IS NOT NULL を使う）
SELECT name FROM employees
WHERE email IS NOT NULL;

